refsection.programlisting:
// Create a full factorial design with :
// 2 levels for the first factor
// 2 levels for the second factor
B=scidoe_ff2n(2)
// Scale into [-1,1]
C=2*B-1;
// Plot this design
scf();
scidoe_plotcube(2);
plot(C(:,1),C(:,2),"bo");

// For three factors
B=scidoe_ff2n(3)
// Scale into [-1,1]
C=2*B-1;
// Plot this design
h = scf();
param3d(C(:,1),C(:,2),C(:,3))
h.children.children.mark_mode="on";
h.children.children.line_mode="off";
h.children.children.mark_size=1;
scidoe_plotcube(3)

// For four factors
B=scidoe_ff2n(4)
